// Fetch tiered RSS/Reddit feeds. 96h lookback. Drops UNDATED items (P3-6) so
// stale-but-dateless entries can't sneak past the window. Carries per-run feed
// telemetry (feeds_total / feeds_ok / candidate_count) for the low-supply alert (P2-12).
const RSS_FEEDS = [
  { url: 'https://tldr.tech/api/rss/ai', source: 'tldr.tech', tier: 1 },
  { url: 'https://hnrss.org/frontpage?q=AI+OR+LLM+OR+Claude+OR+GPT', source: 'news.ycombinator.com', tier: 1 },
  { url: 'https://www.anthropic.com/news/rss.xml', source: 'anthropic.com', tier: 1 },
  { url: 'https://openai.com/blog/rss.xml', source: 'openai.com', tier: 1 },
  { url: 'https://deepmind.google/blog/rss.xml', source: 'deepmind.google', tier: 1 },
  { url: 'https://blog.google/technology/ai/rss/', source: 'blog.google', tier: 1 },
  { url: 'https://simonwillison.net/atom/everything/', source: 'simonwillison.net', tier: 1 },
  { url: 'https://www.latent.space/feed', source: 'latent.space', tier: 1 },
  { url: 'https://www.actuia.com/feed/', source: 'actuia.com', tier: 1 },
  { url: 'https://techcrunch.com/category/artificial-intelligence/feed/', source: 'techcrunch.com', tier: 2 },
  { url: 'https://research.google/blog/rss/', source: 'research.google', tier: 2 },
  { url: 'https://huggingface.co/blog/feed.xml', source: 'huggingface.co', tier: 2 },
  { url: 'https://bair.berkeley.edu/blog/feed.xml', source: 'bair.berkeley.edu', tier: 2 },
  { url: 'https://importai.substack.com/feed', source: 'importai.substack.com', tier: 2 },
  { url: 'https://magazine.sebastianraschka.com/feed', source: 'sebastianraschka.com', tier: 2 },
  { url: 'https://www.technologyreview.com/topic/artificial-intelligence/feed', source: 'technologyreview.com', tier: 2 },
  { url: 'https://www.reddit.com/r/LocalLLaMA/.rss', source: 'reddit.com/r/LocalLLaMA', tier: 2 },
  { url: 'https://mshibanami.github.io/GitHubTrendingRSS/daily/python.xml', source: 'github.com/trending', tier: 2 },
  { url: 'https://www.theverge.com/ai-artificial-intelligence/rss/index.xml', source: 'theverge.com', tier: 3 },
  { url: 'https://www.reddit.com/r/MachineLearning/.rss', source: 'reddit.com/r/MachineLearning', tier: 3 },
  { url: 'http://export.arxiv.org/rss/cs.AI', source: 'arxiv.org/cs.AI', tier: 3 },
  { url: 'http://export.arxiv.org/rss/cs.CL', source: 'arxiv.org/cs.CL', tier: 3 },
  { url: 'https://www.usine-digitale.fr/rss/', source: 'usine-digitale.fr', tier: 3 },
];

const CUTOFF_MS = Date.now() - 96 * 60 * 60 * 1000;

function stripCdata(s = '') {
  return s.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').replace(/<[^>]+>/g, '').trim();
}

function parseRss(xml, source, tier) {
  const out = [];
  const blocks = xml.match(/<(item|entry)[\s\S]*?<\/(item|entry)>/g) || [];
  for (const block of blocks) {
    const title = (block.match(/<title[^>]*>([\s\S]*?)<\/title>/) || [, ''])[1];
    const linkMatch =
      block.match(/<link[^>]*href="([^"]+)"/) ||
      block.match(/<link[^>]*>([\s\S]*?)<\/link>/);
    const link = linkMatch ? linkMatch[1] : '';
    const pub =
      (block.match(/<pubDate[^>]*>([\s\S]*?)<\/pubDate>/) || [, ''])[1] ||
      (block.match(/<published[^>]*>([\s\S]*?)<\/published>/) || [, ''])[1] ||
      (block.match(/<updated[^>]*>([\s\S]*?)<\/updated>/) || [, ''])[1] ||
      (block.match(/<dc:date[^>]*>([\s\S]*?)<\/dc:date>/) || [, ''])[1];
    const desc =
      (block.match(/<description[^>]*>([\s\S]*?)<\/description>/) || [, ''])[1] ||
      (block.match(/<summary[^>]*>([\s\S]*?)<\/summary>/) || [, ''])[1];
    const publishedMs = pub ? Date.parse(pub) : NaN;
    if (!title || !link) continue;
    if (!isFinite(publishedMs)) continue; // P3-6: drop undated items
    out.push({
      title: stripCdata(title),
      url: link.trim(),
      source,
      tier,
      published_ms: publishedMs,
      snippet: stripCdata(desc).slice(0, 400),
      kind: 'rss',
    });
  }
  return out;
}

async function fetchFeed({ url, source, tier }) {
  try {
    const xml = await this.helpers.httpRequest({
      method: 'GET',
      url,
      headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0 Safari/537.36' },
      returnFullResponse: false,
      timeout: 15000,
    });
    return parseRss(typeof xml === 'string' ? xml : String(xml), source, tier);
  } catch (err) {
    console.warn('Feed failed: ' + source + ' ' + err.message);
    return null; // null = failed feed (distinct from empty)
  }
}

const all = [];
let feedsOk = 0;
for (const feed of RSS_FEEDS) {
  const rows = await fetchFeed.call(this, feed);
  if (rows === null) continue;
  feedsOk += 1;
  all.push(...rows);
}

const seen = new Set();
const filtered = all
  .filter((i) => i.published_ms >= CUTOFF_MS)
  .filter((i) => { if (seen.has(i.url)) return false; seen.add(i.url); return true; })
  .sort((a, b) => (a.tier - b.tier) || (b.published_ms - a.published_ms))
  .slice(0, 140);

return [{ json: { items: filtered, count: filtered.length, feeds_total: RSS_FEEDS.length, feeds_ok: feedsOk } }];

// Normalize Apify Twitter rows into our item shape. 48h window. Tweets get
// tier 2 so they interleave with tier-2 RSS in the candidate sort (P1-2).
const CUTOFF_MS = Date.now() - 48 * 60 * 60 * 1000;
const rows = items.map((i) => i.json);
const normalized = rows
  .map((t) => {
    const created = t.createdAt || t.created_at || t.date;
    const ms = created ? Date.parse(created) : NaN;
    const handle = t.author?.userName || t.user?.screen_name || t.username || 'unknown';
    return {
      title: t.text ? t.text.slice(0, 200) : '',
      url: t.url || t.twitterUrl || ('https://x.com/' + handle + '/status/' + (t.id || '')),
      source: 'x.com/@' + handle,
      tier: 2,
      published_ms: ms,
      snippet: t.text || '',
      kind: 'tweet',
      engagement: (t.likeCount || 0) + (t.retweetCount || 0) * 2,
    };
  })
  .filter((t) => t.title && isFinite(t.published_ms) && t.published_ms >= CUTOFF_MS)
  .sort((a, b) => b.engagement - a.engagement)
  .slice(0, 25);

return [{ json: { items: normalized, count: normalized.length } }];

// Merge (append) gives one item per branch, each with its own .items array.
// Flatten, drop URLs already sent in the last 14 days (P1-3), interleave by
// tier-then-recency so tweets reach the curator, tag a monotonic issue number
// from the real sent count (P3-1).
const combined = [];
for (const i of items) {
  if (Array.isArray(i.json?.items)) combined.push(...i.json.items);
}

// Cross-issue dedup: filter out anything shipped recently.
let recentUrls = [];
try {
  const ctx = $('Get Issue Context').first().json;
  recentUrls = Array.isArray(ctx.recent_urls) ? ctx.recent_urls : [];
} catch (e) { recentUrls = []; }
const recentSet = new Set(recentUrls.map((u) => String(u).trim()));

const seen = new Set();
const deduped = combined
  .filter((i) => i && i.url && !recentSet.has(String(i.url).trim()))
  .filter((i) => { const u = String(i.url).trim(); if (seen.has(u)) return false; seen.add(u); return true; })
  .sort((a, b) => ((a.tier || 3) - (b.tier || 3)) || ((b.published_ms || 0) - (a.published_ms || 0)))
  .slice(0, 120);

let sentTotal = 0;
try { sentTotal = Number($('Get Issue Context').first().json.sent_total) || 0; } catch (e) { sentTotal = 0; }
const issueNumber = sentTotal + 1;

return [{ json: { items: deduped, count: deduped.length, issue_number: issueNumber, date_iso: new Date().toISOString(), feeds_ok: (items[0]?.json?.feeds_ok ?? null), feeds_total: (items[0]?.json?.feeds_total ?? null) } }];

// Parse the Claude format-C JSON, detect API errors distinctly from a slow news
// day (P1-4), whitelist URLs against the real candidates (anti-hallucination),
// and set an explicit route: 'error' | 'held' | 'send'.
const reply = $input.first().json;

// P1-4: an Anthropic error body (type:'error') or a missing content array is an
// OUTAGE, not "too few stories". Route it to 'error' so it alerts + is visible,
// instead of masquerading as a held issue.
const apiError = !reply || reply.type === 'error' || !Array.isArray(reply.content) || !reply.content[0]?.text;

const raw = apiError ? '{}' : (reply.content[0].text || '{}');
let parsed;
try {
  let cleaned = String(raw).trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) cleaned = cleaned.slice(first, last + 1);
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {};
}

const issue = $('Combine + Tag Issue').first().json;
const cand = Array.isArray(issue.items) ? issue.items : [];
const validUrls = new Set(cand.map((i) => String(i.url).trim()));
const urlSource = new Map(cand.map((i) => [String(i.url).trim(), String(i.source || '').trim()]));
const clean = (s) => String(s == null ? '' : s).trim();

let featured = Array.isArray(parsed.featured) ? parsed.featured : [];
const fSeen = new Set();
featured = featured
  .map((s) => ({ title: clean(s.title), lines: clean(s.lines), url: clean(s.url), source: clean(s.source) }))
  .filter((s) => s.title && s.lines && validUrls.has(s.url))
  .filter((s) => (fSeen.has(s.url) ? false : (fSeen.add(s.url), true)))
  .map((s) => ({ ...s, source: urlSource.get(s.url) || s.source }))
  .slice(0, 4);

let quickhits = Array.isArray(parsed.quickhits) ? parsed.quickhits : [];
const featuredUrls = new Set(featured.map((f) => f.url));
const qSeen = new Set();
quickhits = quickhits
  .map((s) => ({ line: clean(s.line), url: clean(s.url), source: clean(s.source) }))
  .filter((s) => s.line && validUrls.has(s.url) && !featuredUrls.has(s.url))
  .filter((s) => (qSeen.has(s.url) ? false : (qSeen.add(s.url), true)))
  .map((s) => ({ ...s, source: urlSource.get(s.url) || s.source }))
  .slice(0, 8);

const subject = clean(parsed.subject);
const intro = clean(parsed.intro);
const outro = clean(parsed.outro);
const story_count = featured.length + quickhits.length;
const held = featured.length < 3;
const sent_urls = [...featured.map((f) => f.url), ...quickhits.map((q) => q.url)];

// Low-supply signal (P2-12): too few candidates reached curation.
const candidate_count = cand.length;
const low_supply = candidate_count < 30;

const route = apiError ? 'error' : (held ? 'held' : 'send');

return [{
  json: {
    subject, intro, outro, featured, quickhits,
    story_count, featured_count: featured.length,
    apiError, held, route, low_supply, candidate_count,
    sent_urls,
    issue_number: issue.issue_number,
    date_iso: issue.date_iso,
  },
}];

